+    fn savepoint(&mut self, _cx: &Cx, name: &str) -> Result<()> {
+        self.savepoint_stack.push(SavepointEntry {
+            name: name.to_owned(),
+            write_set_snapshot: self.write_set.clone(),
+            freed_pages_snapshot: self.freed_pages.clone(),
+        });
